    'pri-notebooklm': {
      id: 'pri-notebooklm',
      name: 'NotebookLM',
      cardClass: 'tool-card-notebooklm',
      logo: 'img/notebooklm.png',
      logoAlt: '📓',
      tagline: 'Sube el libro de texto y genera resúmenes, cuestionarios y podcasts para tus alumnos',
      chipNew: false,
      tutClass: 'tut-notebooklm',
      info: [
        '<strong>¿Qué es?</strong> NotebookLM es un asistente de Google basado en IA que trabaja exclusivamente con los documentos que tú le das. No inventa ni busca en internet: analiza tus PDFs, documentos de Drive, vídeos de YouTube o webs y genera resúmenes, guías de estudio, cuestionarios y hasta podcasts en audio a partir de ese material. Ideal para transformar capítulos del libro de texto en recursos de repaso para tus alumnos.',
        '<strong>💡 ¿Por qué usarlo?</strong> En Primaria, preparar material de repaso (resúmenes, fichas de preguntas, cuestionarios) consume mucho tiempo. NotebookLM lo automatiza: subes el PDF del tema y en minutos tienes una guía de estudio con preguntas y respuestas, o un podcast donde dos voces de IA repasan el contenido. Tus alumnos pueden escucharlo en casa como refuerzo. Gratuito con Google Workspace for Education.',
      ],
      steps: [
        { title: 'Abre NotebookLM y crea un cuaderno', desc: 'Un cuaderno por tema o unidad didáctica', detail: 'Ve a <code>notebooklm.google.com</code> e inicia sesión con tu cuenta de Google. Haz clic en <code>Nuevo cuaderno</code> y ponle un nombre descriptivo, por ejemplo: «Tema 4 · El sistema solar - 5.o Primaria» o «Los ecosistemas - 4.o Primaria». Puedes tener hasta 100 cuadernos, uno por cada tema si quieres.' },
        { title: 'Sube tus fuentes', desc: 'Añade el PDF del libro, un vídeo de YouTube o una web educativa', detail: 'Haz clic en <code>Añadir fuente</code> (panel izquierdo). Puedes subir: el PDF del capítulo del libro de texto, documentos de Google Drive, presentaciones de Slides, enlaces a vídeos educativos de YouTube o webs de referencia. Cada cuaderno admite hasta 50 fuentes. NotebookLM leerá y analizará todo automáticamente.' },
        { title: 'Pregunta sobre el contenido', desc: 'Haz preguntas concretas y obtén respuestas basadas en tus fuentes', detail: 'En el cuadro de chat (parte inferior), pregunta lo que necesites. Ejemplos: <code>Resume este tema en 8 puntos clave para alumnos de 10 años</code>, <code>Crea 10 preguntas de verdadero o falso sobre el sistema solar</code>, <code>Explica la fotosíntesis con palabras sencillas</code>. Cada respuesta incluye citas a tus documentos para verificar la información.' },
        { title: 'Genera materiales de repaso', desc: 'Guías de estudio, cuestionarios y podcasts automáticos', detail: 'En el panel derecho encontrarás herramientas para generar automáticamente: <strong>Guías de estudio</strong> con preguntas y respuestas, <strong>Resúmenes</strong> del contenido, <strong>Cuestionarios</strong> tipo test, <strong>Resúmenes de audio</strong> (dos voces de IA comentan el tema como un podcast) y <strong>Resúmenes de vídeo</strong>. Puedes compartir estos materiales con tus alumnos a través de Classroom.' },
      ],
      mission: 'Crea un cuaderno de NotebookLM sobre un tema de tu asignatura de Primaria. Sube el PDF del libro de texto (o un vídeo de YouTube educativo) y genera una guía de estudio o un podcast para que tus alumnos repasen en casa.',
      example: '<strong>💡 Ideas:</strong> Sube el PDF del tema «Los ecosistemas» de Ciencias Naturales de 4.o. Pide a NotebookLM: «Crea un cuestionario de 10 preguntas tipo test con 4 opciones cada una, adaptado a alumnos de 9-10 años, con la respuesta correcta al final». Luego genera un «Audio Overview» y tendrás un podcast del tema que pueden escuchar en casa.',
      link: 'google-pro.html',
      linkLabel: 'Acceder con Google Pro →',
    },

    'pri-gemini-mat': {
      id: 'pri-gemini-mat',
      name: 'Gemini',
      cardClass: 'tool-card-gemini',
      logo: 'img/gemini.png',
      logoAlt: '✦',
      tagline: 'Fichas, exámenes, rúbricas y adaptaciones NEE para tus asignaturas',
      chipNew: false,
      tutClass: 'tut-gemini',
      info: [
        '<strong>¿Qué es?</strong> Gemini es el asistente de IA de Google. Puedes pedirle que cree fichas de actividades, exámenes tipo test o de desarrollo, rúbricas de evaluación sencillas y, lo más valioso, adaptaciones personalizadas para alumnos con Necesidades Educativas Especiales (NEE). La clave está en darle el contexto preciso: asignatura, curso, tema y tipo de material que necesitas.',
        '<strong>⚠️ Importante:</strong> Gemini genera borradores que siempre debes revisar. Nunca incluyas datos personales de alumnos (nombres, diagnósticos concretos) al escribir tus peticiones. Describe el perfil de necesidades sin identificar al alumno, conforme a la normativa de protección de datos.',
      ],
      steps: [
        { title: 'Abre Gemini y define el contexto', desc: 'Dile qué asignatura, curso y tema vas a trabajar', detail: 'Ve a <code>gemini.google.com</code> e inicia sesión. Empieza dándole contexto: <code>Soy maestro/a de Educación Primaria, 4.o curso (alumnos de 9-10 años). Necesito crear materiales para Ciencias Naturales, tema: Los ecosistemas. Sigue la legislación LOMLOE.</code> Cuanto más contexto, mejores resultados.' },
        { title: 'Solicita el material que necesitas', desc: 'Fichas de actividades, exámenes, resúmenes o rúbricas', detail: 'Pide lo que necesites de forma concreta. Ejemplos:<br>• <code>Crea una ficha de actividades sobre los ecosistemas con 5 preguntas de verdadero/falso, 3 de relacionar y 2 de desarrollo corto</code><br>• <code>Genera un examen tipo test de 15 preguntas con 4 opciones sobre este tema, con respuestas al final</code><br>• <code>Diseña una rúbrica de evaluación con 4 niveles para un proyecto sobre los animales</code>' },
        { title: 'Pide la adaptación para NEE', desc: 'Genera versiones adaptadas sin incluir datos personales del alumno', detail: 'Una vez tengas el material base, pide la adaptación: <code>Adapta esta ficha para un alumno con dificultades de comprensión lectora: simplifica el vocabulario, usa frases más cortas, añade apoyo visual con emojis descriptivos y reduce a 8 preguntas.</code> Describe el perfil de necesidades sin identificar al alumno.' },
        { title: 'Revisa, ajusta y exporta', desc: 'Comprueba que el nivel y los contenidos son correctos', detail: 'Lee el material generado con atención: comprueba que los datos son correctos, el vocabulario es adecuado a la edad y las preguntas tienen el nivel esperado. Copia el texto a un Google Doc para maquetarlo. Puedes pedir ajustes: <code>Hazlo más fácil</code>, <code>Añade un dibujo para colorear</code>. La IA te da un borrador sólido; tu criterio profesional hace el resto.' },
      ],
      mission: 'Genera una ficha de actividades o un examen para una de tus asignaturas de Primaria y crea una adaptación para un perfil NEE. Revisa que el contenido sea correcto y adecuado al nivel de tus alumnos.',
      example: '<strong>💡 Ejemplo paso a paso:</strong> 1) Pide a Gemini una ficha de actividades sobre «La multiplicación» para 3.o de Primaria con 10 ejercicios progresivos. 2) Luego pide: «Adapta esta ficha para un alumno con discalculia: reduce a 6 ejercicios, incluye apoyo visual con dibujos, usa números más pequeños y añade un ejemplo resuelto al principio». 3) Copia ambas versiones a Google Docs.',
      link: 'google-pro.html',
      linkLabel: 'Acceder con Google Pro →',
    },

