      name: 'Grok (Aurora)',
      cardClass: 'tool-card-grok',
      logo: 'img/grok.png',
      logoAlt: '𝕏',
      tagline: 'Múltiples opciones por petición para infografías, recreaciones y material didáctico',
      chipNew: true,
      tutClass: 'tut-grok',
